def rainwater_classic(height):
    left = 0
    right = len(height) - 1
    left_max = 0
    right_max = 0
    total = 0
    while left < right:
        if height[left] <= height[right]:
            if height[left] >= left_max:
                left_max = height[left]
            else:
                total += left_max - height[left]
            left += 1
        else:
            if height[right] >= right_max:
                right_max = height[right]
            else:
                total += right_max - height[right]
            right -= 1
    return total

def rainwater_v1(height):
    if len(height) < 2:
        return 0
    top = max(height)
    return sum(top - h for h in height)

def rainwater_v3(height, t, e):
    if len(height) < 2:
        return (0, 0)

    segments = []
    for i, h in enumerate(height):
        segments.append((h, t))
        if i != len(height) - 1:
            segments.append((0, 1))

    n = len(segments)
    left = [0] * n
    right = [0] * n
    high = 0
    for i, (h, _) in enumerate(segments):
        left[i] = high
        if h > high:
            high = h
    high = 0
    for i in range(n - 1, -1, -1):
        h, _ = segments[i]
        right[i] = high
        if h > high:
            high = h

    water = []
    for i, (h, width) in enumerate(segments):
        level = min(left[i], right[i])
        depth = level - h
        water.append(depth * width if depth > 0 else 0)

    total = 0
    evaporated = 0
    i = 0
    while i < n:
        if water[i] == 0:
            i += 1
            continue
        pocket_width = 0
        pocket_volume = 0
        while i < n and water[i] > 0:
            pocket_width += segments[i][1]
            pocket_volume += water[i]
            i += 1
        if pocket_width <= e:
            evaporated += 1
        else:
            total += pocket_volume
    return (total, evaporated)
